# This script prepares PR context information for auto-generated documentation PRs.
# It detects the trigger type (merged PR, direct push, or manual dispatch) and formats
# the PR title and body with relevant context and links.
#
# Expected environment variables:
#   - GITHUB_EVENT_NAME: The GitHub event that triggered the workflow (push, workflow_dispatch, etc.)
#   - GITHUB_SHA: The commit SHA that triggered the workflow
#   - GITHUB_REF_NAME: The branch name (e.g., "main", "release/0.32")
#   - GITHUB_REPOSITORY: The repository in owner/repo format
#   - GITHUB_ACTOR: The user who triggered the workflow (for manual triggers)
#   - GITHUB_OUTPUT: File path to write GitHub Actions output variables
#   - RADIUS_REPO_PATH: Path to the radius repository checkout (defaults to ./radius)

set -euo pipefail

# Configuration
RADIUS_REPO_PATH="${RADIUS_REPO_PATH:-./radius}"

# Change to radius directory to extract commit information
# Note: GITHUB_SHA refers to the triggering commit in the radius repository
cd "${RADIUS_REPO_PATH}"

# Extract commit information
COMMIT_MESSAGE=$(git log -1 --pretty=format:"%s" "${GITHUB_SHA}")
COMMIT_AUTHOR=$(git log -1 --pretty=format:"%an" "${GITHUB_SHA}")

# Determine the source of this workflow run
if [[ "${GITHUB_EVENT_NAME}" == "push" ]]; then
    # Triggered by a push to main or release branch
    # Check if this is a merge commit from a PR
    # GitHub's squash merge format: "Title (#123)" - PR number at end of message
    # This pattern specifically targets squash merges, which is the default for this repo
    if [[ "${COMMIT_MESSAGE}" =~ \(#([0-9]+)\)$ ]]; then
        # Extract PR number from commit message
        PR_NUMBER="${BASH_REMATCH[1]}"
        
        # For merged PRs, try to get the PR title (everything before " (#123)")
        PR_TITLE="${COMMIT_MESSAGE% (#${PR_NUMBER})}"
        
        echo "pr-title=Update auto-generated documentation (PR #${PR_NUMBER})" >> "${GITHUB_OUTPUT}"
        echo "pr-body<<EOF" >> "${GITHUB_OUTPUT}"
        echo "## Autogenerated PR" >> "${GITHUB_OUTPUT}"
        echo "" >> "${GITHUB_OUTPUT}"
        echo "This PR updates the auto-generated reference documentation." >> "${GITHUB_OUTPUT}"
        echo "" >> "${GITHUB_OUTPUT}"
        echo "### Triggered by" >> "${GITHUB_OUTPUT}"
        echo "**Pull Request:** [#${PR_NUMBER} - ${PR_TITLE}](https://github.com/${GITHUB_REPOSITORY}/pull/${PR_NUMBER})" >> "${GITHUB_OUTPUT}"
        echo "**Branch:** \`${GITHUB_REF_NAME}\`" >> "${GITHUB_OUTPUT}"
        echo "**Commit:** [\`${GITHUB_SHA}\`](https://github.com/${GITHUB_REPOSITORY}/commit/${GITHUB_SHA})" >> "${GITHUB_OUTPUT}"
        echo "**Author:** ${COMMIT_AUTHOR}" >> "${GITHUB_OUTPUT}"
        echo "EOF" >> "${GITHUB_OUTPUT}"
    else
        # Regular push commit (not from a PR merge)
        echo "pr-title=Update auto-generated documentation (${GITHUB_REF_NAME})" >> "${GITHUB_OUTPUT}"
        echo "pr-body<<EOF" >> "${GITHUB_OUTPUT}"
        echo "## Autogenerated PR" >> "${GITHUB_OUTPUT}"
        echo "" >> "${GITHUB_OUTPUT}"
        echo "This PR updates the auto-generated reference documentation." >> "${GITHUB_OUTPUT}"
        echo "" >> "${GITHUB_OUTPUT}"
        echo "### Triggered by" >> "${GITHUB_OUTPUT}"
        echo "**Branch:** \`${GITHUB_REF_NAME}\`" >> "${GITHUB_OUTPUT}"
        echo "**Commit:** [\`${GITHUB_SHA}\`](https://github.com/${GITHUB_REPOSITORY}/commit/${GITHUB_SHA})" >> "${GITHUB_OUTPUT}"
        echo "**Author:** ${COMMIT_AUTHOR}" >> "${GITHUB_OUTPUT}"
        echo "**Message:** ${COMMIT_MESSAGE}" >> "${GITHUB_OUTPUT}"
        echo "EOF" >> "${GITHUB_OUTPUT}"
    fi
else
    # Triggered by workflow_dispatch
    echo "pr-title=Update auto-generated documentation (manual trigger)" >> "${GITHUB_OUTPUT}"
    echo "pr-body<<EOF" >> "${GITHUB_OUTPUT}"
    echo "## Autogenerated PR" >> "${GITHUB_OUTPUT}"
    echo "" >> "${GITHUB_OUTPUT}"
    echo "This PR updates the auto-generated reference documentation." >> "${GITHUB_OUTPUT}"
    echo "" >> "${GITHUB_OUTPUT}"
    echo "### Triggered by" >> "${GITHUB_OUTPUT}"
    echo "**Trigger:** Manual workflow dispatch" >> "${GITHUB_OUTPUT}"
    echo "**Triggered by:** @${GITHUB_ACTOR}" >> "${GITHUB_OUTPUT}"
    echo "**Branch:** \`${GITHUB_REF_NAME}\`" >> "${GITHUB_OUTPUT}"
    echo "**Commit:** [\`${GITHUB_SHA}\`](https://github.com/${GITHUB_REPOSITORY}/commit/${GITHUB_SHA})" >> "${GITHUB_OUTPUT}"
    echo "**Commit Message:** ${COMMIT_MESSAGE}" >> "${GITHUB_OUTPUT}"
    echo "EOF" >> "${GITHUB_OUTPUT}"
fi
